import{c as t,Q as a,j as n,m as r}from"./chunks/framework.BXc4yaFE.js";const l=JSON.parse('{"title":"The Rundown AI — 2026-04-21","description":"","frontmatter":{"title":"The Rundown AI — 2026-04-21","date":"2026-04-21T00:00:00.000Z","source":"The Rundown AI","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-04/2026-04-21-the-rundown-ai.md","filePath":"research/ai-news/2026-04/2026-04-21-the-rundown-ai.md","lastUpdated":1779898012000}'),o={name:"research/ai-news/2026-04/2026-04-21-the-rundown-ai.md"};function i(s,e,m,p,u,c){return a(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="🗞️-the-rundown-ai-—-2026-04-21" tabindex="-1">🗞️ The Rundown AI — 2026-04-21 <a class="header-anchor" href="#🗞️-the-rundown-ai-—-2026-04-21" aria-label="Permalink to &quot;🗞️ The Rundown AI — 2026-04-21&quot;">​</a></h1><blockquote><p>每日 AI 產業動態，通俗易懂、密度高 來源：<a href="https://rss.beehiiv.com/feeds/2R3C6Bt5wj.xml" target="_blank" rel="noreferrer">The Rundown AI</a></p></blockquote><hr><h2 id="sergey-brin-commits-deepmind-to-a-claude-catch-up" tabindex="-1"><a href="https://www.therundown.ai/p/sergey-brin-commits-deepmind-to-a-claude-catch-up" target="_blank" rel="noreferrer">Sergey Brin commits DeepMind to a Claude catch-up</a> <a class="header-anchor" href="#sergey-brin-commits-deepmind-to-a-claude-catch-up" aria-label="Permalink to &quot;[Sergey Brin commits DeepMind to a Claude catch-up](https://www.therundown.ai/p/sergey-brin-commits-deepmind-to-a-claude-catch-up)&quot;">​</a></h2><p><em>🗞️ The Rundown AI | 2026-04-21</em></p><p><a href="./">Read Online</a> | <a href="https://www.therundown.ai/subscribe?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=sergey-brin-commits-deepmind-to-a-claude-catch-up" target="_blank" rel="noreferrer">Sign Up</a> | <a href="https://therundownai.typeform.com/to/kraZ1TSO?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=sergey-brin-commits-deepmind-to-a-claude-catch-up" target="_blank" rel="noreferrer">Advertise</a></p><p><a href="https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The%20Rundown%20Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_421&amp;utm_content=rundown_primary_421" target="_blank" rel="noreferrer"></a></p><p>Good morning, AI enthusiasts. Catching Anthropic&#39;s lead in coding just became Sergey Brin&#39;s personal project.</p><p>The once-retired Google co-founder is now reportedly running a DeepMind “strike team” focused on closing Gemini&#39;s internal coding gap with Claude — with Brin framing the push as the shortest route to the holy grail of self-improving AI.</p><p>In today’s AI rundown:</p><p>Brin mobilizes DeepMind to chase Anthropic on code</p><p>Moonshot AI’s Kimi K2.6 closes open-source gap</p><p>Create high-converting landing pages in Claude Design</p><p>Adobe’s new agentic AI platform for enterprises</p><p>4 new AI tools, community workflows, and more</p><p>LATEST DEVELOPMENTS</p><p>GOOGLE</p><p>💻 <a href="https://www.theinformation.com/articles/google-creates-strike-team-improve-coding-models?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=sergey-brin-commits-deepmind-to-a-claude-catch-up" target="_blank" rel="noreferrer">Brin mobilizes DeepMind to chase Anthropic on code</a></p><p>Image source: Lovart / The Rundown</p><p>The Rundown: Google co-founder Sergey Brin is personally <a href="https://www.theinformation.com/articles/google-creates-strike-team-improve-coding-models?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=sergey-brin-commits-deepmind-to-a-claude-catch-up" target="_blank" rel="noreferrer">rallying</a> DeepMind to out-code Anthropic with Gemini, according to The Information — creating a new “strike team” and pitching the effort to staff as the shortest route to self-improving AI systems.</p><p>The details:</p><p>Research engineer Sebastian Borgeaud, who previously ran DeepMind&#39;s pretraining, is leading the group under CTO Koray Kavukcuoglu and Brin.</p><p>In an internal memo, Brin told staff the real prize is AI that trains the next AI, with coding being the capability that gets Gemini there.</p><p>DeepMind researchers reportedly rate Claude&#39;s code-writing above Gemini&#39;s internally, which kicked off Brin&#39;s push for a dedicated team.</p><p>Gemini engineers now have to use Google&#39;s internal agent tools on complex tasks, with usage tracked on a company leaderboard called Jetski.</p><p>Why it matters: After dominating the AI conversation towards the end of 2025, Google has had a slow start to 2026. But Brin&#39;s push isn&#39;t a product response — it&#39;s an internal one, and the strike team&#39;s real job is to automate Google itself, closing the gap with deeply embedded AI systems already operating inside Anthropic and OpenAI.</p><p>TOGETHER WITH YOU.COM</p><p>🐌 [Is your API latency metric lying to you?](<a href="https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The" target="_blank" rel="noreferrer">https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The</a> Rundown Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_421&amp;utm_content=rundown_primary_421)</p><p>[](<a href="https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The" target="_blank" rel="noreferrer">https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The</a> Rundown Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_421&amp;utm_content=rundown_primary_421)</p><p>The Rundown: Most teams pick an API by checking a benchmark table and calling it done—a shortcut that could miss what really matters in production. This guide from [You.com](<a href="https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The" target="_blank" rel="noreferrer">https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The</a> Rundown Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_421&amp;utm_content=rundown_primary_421) explains why raw latency is a misleading signal and what to measure instead.</p><p>What you&#39;ll get:</p><p>Why p50 latency hides the failures your users actually experience</p><p>The &quot;time-to-useful-result&quot; framework that captures what benchmarks leave out</p><p>Four hidden cost drivers that show up in your logs, not vendor tables</p><p>How to evaluate APIs at your actual concurrency levels, not the demo conditions</p><p>Stop optimizing for the wrong number. [Learn what to measure instead](<a href="https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The" target="_blank" rel="noreferrer">https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The</a> Rundown Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_421&amp;utm_content=rundown_primary_421).</p><p>MOONSHOT AI</p><p>🔓 <a href="https://www.kimi.com/blog/kimi-k2-6?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=sergey-brin-commits-deepmind-to-a-claude-catch-up" target="_blank" rel="noreferrer">Moonshot AI’s Kimi K2.6 closes open-source gap</a></p><p>Image source: Moonshot AI</p><p>The Rundown: Moonshot AI’s Kimi <a href="https://www.kimi.com/blog/kimi-k2-6?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=sergey-brin-commits-deepmind-to-a-claude-catch-up" target="_blank" rel="noreferrer">open-sourced</a> K2.6, a new agentic coding model that nears or outperforms models like GPT-5.4, Opus 4.6, and Gemini 3.1 Pro across top benchmarks for reasoning, coding, and more at a fraction of the cost.</p><p>The details:</p><p>K2.6 beats GPT-5.4, Opus 4.6, and Gemini 3.1 Pro on benchmarks including Humanity’s Last Exam w/ tools (reasoning) and SWE-Bench Pro (coding).</p><p>On long-horizon work, K2.6 can work for 12+ hours straight across 4,000+ tool calls, with Kimi showing it refactoring an 8-year-old codebase in demos.</p><p>Always-on agents like OpenClaw and Hermes now run on K2.6, with Kimi reporting one internal agent operated autonomously for five days straight.</p><p>K2.6’s agent swarms can now spin up 300 parallel sub-agents at the same time to complete tasks, triple the amount of its K2.5 predecessor.</p><p>Why it matters: Dario Amodei just said open-source and China are 6-12 months behind frontier labs, and while that may be true of internal releases, public systems are looking a lot closer. Given frustrations over usage rates and the rise of autonomous agents, K2.6 looks like a powerful, cost-effective new option for agentic workflows.</p><p>AI TRAINING</p><p>🧑‍🎨 <a href="https://app.therundown.ai/guides/how-to-design-a-high-converting-landing-page-in-claude-design?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=sergey-brin-commits-deepmind-to-a-claude-catch-up" target="_blank" rel="noreferrer">Create high-converting landing pages in Claude Design</a></p><p><a href="https://app.therundown.ai/guides/how-to-design-a-high-converting-landing-page-in-claude-design?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=sergey-brin-commits-deepmind-to-a-claude-catch-up" target="_blank" rel="noreferrer"></a></p><p>The Rundown: In this guide, you will learn how to use Claude Design, Anthropic’s new design tool, to generate four mockup variations of your website’s landing page.</p><p>Step-by-step:</p><p>Go to claude.ai/design, select the wireframe option, click create, and write: who the page is for, what you’re selling, and the action a visitor should take”</p><p>Find and screenshot a landing page you like. Try searching “top landing pages in [your niche]” and the checkout pane of a site that does millions of daily transactions, like Amazon, eBay, or PayPal</p><p>Add the screenshots to your brief, and tell Claude to create four variations of the mockup. Answer any follow-ups, and wait 2-5 minutes for results</p><p>Click any element and leave a note like &quot;rewrite this CTA to be outcome-specific&quot; or &quot;add a testimonial.&quot; Claude applies the changes to refine outputs</p><p>Pro tip: Click Share &gt; Handoff to Claude Code &gt; Send to Claude Code Web to get Claude Code to build and deploy the final website for you.</p><p>PRESENTED BY SLACK</p><p>🤖 <a href="https://slack.com/resources/why-use-slack/teams-work-smarter-with-slackbot-and-ai?d=701ed00001424HwAAI&amp;nc=701ed0000143gMkAAI&amp;utm_source=therundownai&amp;utm_medium=tp_email&amp;utm_campaign=amer_us_slack-invoice_&amp;utm_content=cross-segment_all-strategic-therundownai-slackbotapr21_701ed00001424HwAAI_english_teams-work-smarter-with-slackbot-and-ai" target="_blank" rel="noreferrer">Work smarter, not harder with Slackbot</a></p><p><a href="https://slack.com/resources/why-use-slack/teams-work-smarter-with-slackbot-and-ai?d=701ed00001424HwAAI&amp;nc=701ed0000143gMkAAI&amp;utm_source=therundownai&amp;utm_medium=tp_email&amp;utm_campaign=amer_us_slack-invoice_&amp;utm_content=cross-segment_all-strategic-therundownai-slackbotapr21_701ed00001424HwAAI_english_teams-work-smarter-with-slackbot-and-ai" target="_blank" rel="noreferrer"></a></p><p>The Rundown: Your team is already using AI tools. But are they actually getting smarter results? Slackbot, Slack&#39;s built-in AI, turns your entire workspace into a productivity engine — surfacing answers, drafting content, and automating the busywork so your team can focus on what matters.</p><p>In this free guide, you&#39;ll discover:</p><p>How Slackbot synthesizes conversations, files, and apps for instant answers</p><p>Ways to automate routine tasks without writing a single line of code</p><p>How teams are using AI to move faster and collaborate more effectively</p><p><a href="https://slack.com/resources/why-use-slack/teams-work-smarter-with-slackbot-and-ai?d=701ed00001424HwAAI&amp;nc=701ed0000143gMkAAI&amp;utm_source=therundownai&amp;utm_medium=tp_email&amp;utm_campaign=amer_us_slack-invoice_&amp;utm_content=cross-segment_all-strategic-therundownai-slackbotapr21_701ed00001424HwAAI_english_teams-work-smarter-with-slackbot-and-ai" target="_blank" rel="noreferrer">Read the free guide</a>.</p><p>ADOBE</p><p>🤖 <a href="https://news.adobe.com/news/2026/04/adobe-redefines-custome-experience?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=sergey-brin-commits-deepmind-to-a-claude-catch-up" target="_blank" rel="noreferrer">Adobe’s new agentic AI platform for enterprises</a></p><p>Image source: Adobe</p><p>The Rundown: Adobe just <a href="https://news.adobe.com/news/2026/04/adobe-redefines-custome-experience?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=sergey-brin-commits-deepmind-to-a-claude-catch-up" target="_blank" rel="noreferrer">introduced</a> CX Enterprise at its Adobe Summit, a new agentic platform built to help businesses coordinate marketing, content, and customer interactions through networks of AI agents.</p><p>The details:</p><p>CX Enterprise weaves three pillars under one agentic orchestration layer: brand visibility, content supply chain, and customer engagement.</p><p>CX Enterprise Coworker assembles the correct agents and tools based on a specific user goal, creating a plan and executing multi-step actions.</p><p>Adobe’s Marketing Agent now plugs into systems like ChatGPT, Claude, Gemini, and Copilot, coordinating between the agents and Adobe apps.</p><p>The company is also launching an agent skills catalog, enabling enterprises to create reusable, customizable workflows within the platform.</p><p>Why it matters: The entire design world is moving toward agentic workflows, with Figma Agents, Canva Agents, and Adobe all jockeying for position. The bigger threat is the labs cutting out the middleman: Launches like Claude Design and every subsequent improvement will make legacy orchestration paths more difficult.</p><p>QUICK HITS</p><p>🛠️ <a href="https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=sergey-brin-commits-deepmind-to-a-claude-catch-up" target="_blank" rel="noreferrer">Trending AI Tools</a></p><p>🤖 <a href="http://scrunch.com/airundown?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=sergey-brin-commits-deepmind-to-a-claude-catch-up" target="_blank" rel="noreferrer">Scrunch</a> - See how AI interprets your site, run a free audit, and unlock the new way to reach customers*</p><p>⚙️ <a href="https://www.rundown.ai/tools/kimi-k2-6?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=sergey-brin-commits-deepmind-to-a-claude-catch-up" target="_blank" rel="noreferrer">Kimi K2.6</a> - Moonshot AI&#39;s powerful open-source coding and agent model</p><p>🧠 <a href="https://x.com/OpenAIDevs/status/2046288243768082699?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=sergey-brin-commits-deepmind-to-a-claude-catch-up" target="_blank" rel="noreferrer">Chronicle</a> - OpenAI&#39;s Codex feature that uses screen context for memory</p><p>🚀 <a href="http://www.rundown.ai/tools/qwen3-6-plus?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=sergey-brin-commits-deepmind-to-a-claude-catch-up" target="_blank" rel="noreferrer">Qwen3.6-Plus</a> - Alibaba&#39;s new AI with a 1M context window, strong coding</p><p>*Sponsored Listing</p><p>📰 <a href="https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=sergey-brin-commits-deepmind-to-a-claude-catch-up" target="_blank" rel="noreferrer">Everything else in AI today</a></p><p>OpenAI <a href="https://x.com/OpenAIDevs/status/2046288243768082699?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=sergey-brin-commits-deepmind-to-a-claude-catch-up" target="_blank" rel="noreferrer">rolled out</a> Chronicle, a Codex preview feature that runs background agents capturing your screen to build persistent memories, limited initially to Pro users on Mac.</p><p>Ex-Meta chief AI scientist Yann LeCun <a href="https://x.com/ylecun/status/2045610129119117574?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=sergey-brin-commits-deepmind-to-a-claude-catch-up" target="_blank" rel="noreferrer">said</a> people shouldn’t listen to Dario Amodei about AI’s impact on labor markets, or “Sam, Yoshua, Geoff, or me”, saying economists have the most important perspective.</p><p>Lovable <a href="https://x.com/Lovable/status/2046270357674299623?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=sergey-brin-commits-deepmind-to-a-claude-catch-up" target="_blank" rel="noreferrer">denied</a> reports that it suffered a data breach after users flagged that public project chats were visible, saying the issue was a documentation failure.</p><p>Tinder and Zoom <a href="https://www.bbc.com/news/articles/cp9vppem4evo?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=sergey-brin-commits-deepmind-to-a-claude-catch-up" target="_blank" rel="noreferrer">partnered</a> with Sam Altman&#39;s World, letting users get &quot;proof of humanity&quot; badges via iris scans to combat AI bots and deepfakes.</p><p>Anthropic <a href="https://www.anthropic.com/news/anthropic-amazon-compute?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=sergey-brin-commits-deepmind-to-a-claude-catch-up" target="_blank" rel="noreferrer">expanded</a> its Amazon deal for 5 GW in compute, with the tech giant investing up to $25B more into Anthropic in exchange for its $100B+ AWS commitment.</p><p>Recursive Superintelligence <a href="https://archive.ph/HeCnJ?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=sergey-brin-commits-deepmind-to-a-claude-catch-up#selection-1599.0-2065.82" target="_blank" rel="noreferrer">raised</a> $500M at a $4B valuation, with the four-month-old startup founded by OAI and Deepmind alumni building AI that improves itself.</p><p>COMMUNITY</p><p>🤝 <a href="https://docs.google.com/forms/d/e/1FAIpQLSfH4UPzu72HTpdb08Qlm-0dLwKJIjdcAwCcAvVywcHD6mwKig/viewform?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=sergey-brin-commits-deepmind-to-a-claude-catch-up" target="_blank" rel="noreferrer">Community AI workflows</a></p><p>Every newsletter, we showcase how a reader is using AI to work smarter, save time, or make life easier.</p><p>Today’s workflow comes from reader Julie N. in Grand Junction, CO:</p><p>&quot;As a digital marketer, I use ChatGPT as my assistant. I will feed all of my information about a client&#39;s Google Ads needs into it, including budget, landing page, and let it design keyword-appropriate headlines and descriptions, set the ad strategy, and recommend additional campaign options.</p><p>Also, I will take my stream-of-consciousness thoughts about a potential SEO package and create a front-facing &amp; admin-side PDF that I can share with potential clients.”</p><p>How do you use AI? Tell us <a href="https://docs.google.com/forms/d/e/1FAIpQLSfH4UPzu72HTpdb08Qlm-0dLwKJIjdcAwCcAvVywcHD6mwKig/viewform?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=sergey-brin-commits-deepmind-to-a-claude-catch-up" target="_blank" rel="noreferrer">here</a>.</p><p>🎓 <a href="https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=sergey-brin-commits-deepmind-to-a-claude-catch-up" target="_blank" rel="noreferrer">Highlights: News, Guides &amp; Events</a></p><p>Read our last AI newsletter: <a href="https://www.rundown.ai/articles/claude-comes-for-the-design-stack?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=sergey-brin-commits-deepmind-to-a-claude-catch-up" target="_blank" rel="noreferrer">Claude comes for the design stack</a></p><p>Read our last Tech newsletter: <a href="https://www.rundown.ai/articles/spacex-buys-up-a-lot-of-cybertrucks?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=sergey-brin-commits-deepmind-to-a-claude-catch-up" target="_blank" rel="noreferrer">SpaceX buys up a lot of Cybertrucks</a></p><p>Read our last Robotics newsletter: <a href="https://www.rundown.ai/articles/humanoid-smokes-half-marathon-record?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=sergey-brin-commits-deepmind-to-a-claude-catch-up" target="_blank" rel="noreferrer">Humanoid smokes half marathon record</a></p><p>Today’s AI tool guide: <a href="https://app.therundown.ai/guides/how-to-design-a-high-converting-landing-page-in-claude-design?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=sergey-brin-commits-deepmind-to-a-claude-catch-up" target="_blank" rel="noreferrer">Design landing pages that convert in Claude Design</a></p><p>See you soon,</p><p>Rowan, Joey, Zach, Shubham, and Jennifer — the humans behind The Rundown</p><hr>',104)])])}const h=t(o,[["render",i]]);export{l as __pageData,h as default};
